+    fn load_cursor_valid_json_wrong_schema_returns_error() {
+        let dir = tempdir().expect("tempdir");
+        let cursor_path = dir.path().join("cursor.json");
+        // Valid JSON but missing required fields (last_export_rfc3339, last_run_count).
